  ('disabled-6e2f88c7-moex-00027', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-e733516d', 'sub-disabled-6e2f88c7-05', NULL, 'essay', '甲向管轄法院起訴乙，並主張被告對原告為詐欺，以100萬元購買原告的
M機器，被告已取得 M，卻未給付原告約定價金；原告已撤銷自己的意思
表示，請求法院命被告將 M 機器返還予原告，並預備請求命被告給付價金
100萬元。如法院經審理後，認為原告的預備請求有理由，則應如何裁判？
（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "2f4dea70c106", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0405", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00028', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-e733516d', 'sub-disabled-6e2f88c7-05', NULL, 'essay', '國中畢業之甲涉犯毒品危害防制條例，檢察官對甲於訊問前告以：「我答
應你差不多這個刑度好嗎？會去跟法官講，但我不是法官，我不行現在就
答應你會判多久，但就是差不多是 2 年 7 個月、8 個月左右、……我有跟
你答應差不多這個刑度，我會跟公訴檢察官說。」等詞，並訊以：「所以
我們現在說這麼久，就是你願意承認你買來以後要賣就對了。」被告甲即
回答：「嗯。」等語。試論甲之自白是否有證據能力？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "2f4dea70c106", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0405", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00029', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-e733516d', 'sub-disabled-6e2f88c7-05', NULL, 'essay', '被告甲於民國 88 年涉犯貪污治罪條例第 6 條第 2 項、第 1 項第 5 款圖利
未遂罪嫌，經檢察官提起公訴，因審理期間貪污治罪條例修法，廢除該條
項款之處罰未遂犯，法院依法諭知免訴判決，被告甲不服原審判決，具上
訴狀云：「上訴人並無檢察官起訴書所載之犯罪事實，原判決以犯罪後法
律已廢止其刑罰為理由，諭知免訴，原判決雖諭知免訴，然基本上仍認上
訴人犯罪，況新修正之條文並未廢止其刑罰，僅修改為處罰既遂犯，因此
就未遂犯而言，比較新舊法，應諭知上訴人無罪等語。」試論上訴法院應
如何裁判？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "2f4dea70c106", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0405", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00030', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'essay', '甲死亡後，其繼承人有乙、丙、丁、戊等 4 人，並由乙保管甲所遺留
之現金新臺幣（下同）1,000 萬元、房屋及其坐落之土地各一筆。今
國稅局核課甲之遺產稅為 400 萬元，且業已通知甲之上開繼承人依
限繳納，然丙、丁、戊 3人均不理會，且不願意分割遺產，乙遂以自
己之固有財產先行繳納完畢。乙以自己之固有財產繳納遺產稅後，得
否依民法規定，逕行訴請丙、丁、戊各應給付乙100 萬元？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0402", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00031', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'essay', '甲夫與乙妻結婚後，因時常意見不合而爭吵，某日甲夫與單身女子丙
發生婚外情，經乙妻捉姦在床，乙遂以甲與丙合意性交為由，訴請甲、
丙二人，應負非財產上損害賠償責任新臺幣 200萬元，試申論其請求
權之基礎為何？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0402", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00032', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'single_choice', '下列何者是形成權？', '["民法第144條消滅時效抗辯權", "民法第359條減少價金請求權", "民法第348條之交付買賣標的物請求權", "合意解除契約 30840"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00033', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'single_choice', '關於主物與從物之敘述，下列何者錯誤？', '["房屋非為土地之從物", "依附於第2層樓房之未具獨立性之第3層附屬建物，皆為原建築物之從物", "工廠之機器生財為該工廠之從物", "汽車之備胎為汽車之從物"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00034', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'single_choice', '下列何者不屬於消滅時效之中斷事由？', '["因天災致不能行使請求權", "債權人以郵局存證信函向債務人通知債務履行", "債務人對債權人承認其權利之存在", "債權人對債務人提起民事訴訟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00035', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'single_choice', '下列何種法律行為，不屬於違反公共秩序或善良風俗而歸於無效者？', '["子女甲乙於其父母健在時預立分管合約為財產之瓜分", "有婦之夫甲誘使乙女同居，而將其所有A地之所有權移轉登記於乙女， 並約定一旦終止同居關係，須將A地返還", "甲與乙有金錢糾紛，乙則以言語恐嚇甲和解，甲於和解契約同意以分期 之方式清償債務", "夫妻甲乙間為恐一方於日後或有虐待或侮辱他方情事，而預立離婚契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00036', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'single_choice', '關於附條件法律行為之敘述，下列何者錯誤？', '["條件之成就於法律行為成立時已確定者，倘若該條件為停止條件，認為 法律行為無條件", "條件之不成就於法律行為成立時已確定者，倘若該條件為停止條件，則 該法律行為無效", "條件之成就於法律行為成立時已確定者，倘若該條件為解除條件，則該 法律行為有效", "條件之不成就於法律行為成立時已確定者，倘若該條件為解除條件，則 該法律行為認為無條件"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL)
